def heuristic_options_bias_from_spy_rsi(stats: dict, today_stats: dict) -> dict | None:
    """Auto-adjust options-momentum side_bias based on SPY RSI regime.
    SPY RSI >= 72 => short (PUT side); clears when RSI <= 45.
    Returns {side_bias, reason} or None if no change needed.
    """
    rsi_data = today_stats.get("rsi_snapshot", {}).get("SPY", {})
    spy_rsi = rsi_data.get("today", 50)
    current_bias = stats.get("side_bias")
    if spy_rsi >= 72 and current_bias != "short":
        return {"side_bias": "short", "reason": f"SPY RSI={spy_rsi:.0f} >= 72 overbought — PUT side"}
    if spy_rsi <= 45 and current_bias == "short":
        return {"side_bias": None, "reason": f"SPY RSI={spy_rsi:.0f} <= 45 — overbought thesis invalidated"}
    return None

