class TestOptionsBiasFromSpyRsi(unittest.TestCase):
    def test_sets_short_when_overbought_and_bias_none(self):
        stats = {"side_bias": None}
        today = {"rsi_snapshot": {"SPY": {"today": 73}}}
        r = heuristic_options_bias_from_spy_rsi(stats, today)
        self.assertIsNotNone(r)
        self.assertEqual(r["side_bias"], "short")
    def test_no_change_already_short_overbought(self):
        stats = {"side_bias": "short"}
        today = {"rsi_snapshot": {"SPY": {"today": 72}}}
        self.assertIsNone(heuristic_options_bias_from_spy_rsi(stats, today))
    def test_clears_short_when_spy_neutral(self):
        stats = {"side_bias": "short"}
        today = {"rsi_snapshot": {"SPY": {"today": 44}}}
        r = heuristic_options_bias_from_spy_rsi(stats, today)
        self.assertIsNotNone(r)
        self.assertIsNone(r["side_bias"])
    def test_no_change_neutral_range(self):
        stats = {"side_bias": None}
        today = {"rsi_snapshot": {"SPY": {"today": 60}}}
        self.assertIsNone(heuristic_options_bias_from_spy_rsi(stats, today))
